from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash
import jwt
from functools import wraps

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key'
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:////tmp/test.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    password = db.Column(db.String(120), nullable=False)

def authenticate(username: str, password: str):
    user = User.query.filter_by(username=username).first()
    if not user or not check_password_hash(user.password, password):
        return False
    return jwt.encode({'id': user.id}, app.config['SECRET_KEY'], algorithm="HS256")

def require_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization')
        if not token:
            return jsonify({'message': 'Missing Authorization Header'}), 403
        try:
            user_id = jwt.decode(token[7:], app.config['SECRET_KEY'], algorithms=["HS256"])['id']
            current_user = User.query.get(user_id)
            if not current_user:
                return jsonify({'message': 'Invalid Token'}), 403
        except Exception as e:
            print(str(e))
            return jsonify({'message': 'Invalid Token'}), 403
        return f(*args, **kwargs)
    return decorated

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    password = generate_password_hash(data['password'], method='sha256')
    new_user = User(username=data['username'], password=password)
    db.session.add(new_user)
    db.session.commit()
    return jsonify({'message': 'New user created!'})

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    token = authenticate(data['username'], data['password'])
    if not token:
        return jsonify({'message': 'Invalid Credentials!'}), 403
    return jsonify({'token': token})

@app.route('/protected', methods=['GET'])
@require_auth
def protected():
    return jsonify({'message': 'Access Granted!'})